(function () {
  'use strict';

  function back2top() {
    var $window = $(window);
    var $btn = $('#back-to-top');

    $window.on('scroll', function () {
      $window.scrollTop() > 50 ? $btn.fadeIn() : $btn.fadeOut();
    });

    $btn.on('click', function () {
      $window.scrollTop(0);
    });
  }

  function loadTooptip() {
    var tooltipTriggerList = document.querySelectorAll('[data-bs-toggle="tooltip"]');
    Array.prototype.slice.call(tooltipTriggerList).map(function (tooltipTriggerEl) {
      return new bootstrap.Tooltip(tooltipTriggerEl);
    });
  }

  function modeWatcher() {
    var $toggleElem = $('.mode-toggle');

    if ($toggleElem.length === 0) {
      return;
    }

    $toggleElem.off().on('click', function (e) {
      var $target = $(e.target);
      var $btn = $target.prop('tagName') === 'BUTTON' ? $target : $target.parent();

      modeToggle.flipMode();
      $btn.trigger('blur');
    });
  }

  function sidebarExpand() {
    var $body = $('body');
    var isExpanded = false;

    function toggle() {
      isExpanded === false ? $body.attr('sidebar-display', '') : $body.removeAttr('sidebar-display');
      isExpanded = !isExpanded;
    }

    $('#sidebar-trigger').on('click', toggle);
    $('#mask').on('click', toggle);
  }

  function initLocaleDatetime() {
    dayjs.locale($('html').attr('lang').substring(0, 2));
    dayjs.extend(window.dayjs_plugin_localizedFormat);

    $('[data-ts]').each(function () {
      var $this = $(this);
      var date = dayjs.unix(Number($this.attr('data-ts')));
      $this.text(date.format($this.attr('data-df')));
      $this.removeAttr('data-ts').removeAttr('data-df');

      if ($this.attr('data-bs-toggle') === 'tooltip') {
        $this.attr('data-bs-title', date.format('llll'));
        new bootstrap.Tooltip($this);
      }
    });
  }

  function imgLazy() {
    var $images = $('#core-wrapper img[data-src]');

    if ($images.length <= 0) {
      return;
    }

    function stopShimmer($node) {
      $node.parent().removeClass('shimmer');
    }

    document.addEventListener('lazyloaded', function (e) {
      stopShimmer($(e.target));
    });

    $images.each(function () {
      if ($(this).hasClass('ls-is-cached')) {
        stopShimmer($(this));
      }
    });
  }

  function imgPopup() {
    if ($('.popup').length <= 0) {
      return;
    }

    $('.popup').magnificPopup({
      type: 'image',
      closeOnContentClick: true,
      showCloseBtn: false,
      zoom: {
        enabled: true,
        duration: 300,
        easing: 'ease-in-out'
      }
    });
  }

  function initClipboard() {
    var clipboardSelector = '.code-header>button';
    if ($(clipboardSelector).length && typeof ClipboardJS !== 'undefined') {
      new ClipboardJS(clipboardSelector, {
        target: function (trigger) {
          return trigger.parentNode.nextElementSibling.querySelector('code .rouge-code');
        }
      });
    }

    $('#copy-link').on('click', function () {
      navigator.clipboard.writeText(window.location.href);
    });
  }

  function toc() {
    if (document.querySelector('#core-wrapper h2,#core-wrapper h3')) {
      tocbot.init({
        tocSelector: '#toc',
        contentSelector: '.post-content',
        ignoreSelector: '[data-toc-skip]',
        headingSelector: 'h2, h3',
        orderedList: false,
        scrollSmooth: false
      });
    }
  }

  back2top();
  loadTooptip();
  modeWatcher();
  sidebarExpand();
  imgLazy();
  imgPopup();
  initLocaleDatetime();
  initClipboard();
  toc();
})();
